const input=$input.all().map(i => i.json);
const windowA=input[0];
const windowB=input[1];

// Total repo counts for normalization
const totalA=Object.values(windowA).reduce((s,v) => s+v, 0);
const totalB=Object.values(windowB).reduce((s,v) => s+v, 0);

if (totalA===0)
  throw new Error('Window A returned 0 repos — check fetch node or API filters');
if (totalB===0) 
  throw new Error('Window B returned 0 repos — check fetch node or API filters');

const allLanguages=[...new Set([...Object.keys(windowA), ...Object.keys(windowB)])];

const results=[];

for (const lang of allLanguages) {
  const countA=windowA[lang] || 0;
  const countB=windowB[lang] || 0;

  // Minimum presence filter — ignore micro languages
  // Must appear at least 3 times across both windows
  if (countA + countB < 3) continue;

  // Share = this language's % of all repos in that window
  const shareA=countA/totalA;
  const shareB=countB/totalB;

  let category;
  let percentChange=null;

  if(countA===0) 
    // Present in older window, absent in recent → dropped off 
    category='Dead';
   else if(countB===0) 
    // Absent in older window, present in recent → newly emerging
    category='New';
   else {
    // Both windows have data — compare market share
    percentChange=Math.round(((shareA-shareB)/shareB) * 100);

    if(percentChange>20) 
      category='Rising';
    else if(percentChange<-20) 
      category='Declining';
    else 
      category='Stable';
  }

  results.push({
    json: {
      language: lang,
      countA,
      countB,
      shareA: parseFloat((shareA*100).toFixed(2)),
      shareB: parseFloat((shareB*100).toFixed(2)),
      percentChange,
      repoChange: `${countB} → ${countA}`,
      category
    }
  });
}

// Sort: Rising first, then New, Declining, Dead, Stable — by percentChange within each
const order={ Rising:0, New:1, Declining:2, Dead:3, Stable:4};
results.sort((a,b) => {
  const catDiff=order[a.json.category] - order[b.json.category];
  if (catDiff!==0) return catDiff;
  return (b.json.percentChange || 0) - (a.json.percentChange || 0);
});

return results;

const items = $input.all().map(i => i.json);

const rising = items.filter(i => i.category === 'Rising');
const declining = items.filter(i => i.category === 'Declining');
const newLangs = items.filter(i => i.category === 'New');
const dead = items.filter(i => i.category === 'Dead');
const stable = items.filter(i => i.category === 'Stable');

const fmt = (lang) => {
  if (lang.percentChange!==null) {
    const dir=lang.percentChange > 0 ? '+' : '';
    return `${lang.language}: ${dir}${lang.percentChange}% share change (${lang.shareB}% → ${lang.shareA}%) | ${lang.repoChange} repos`;
  }
  return `${lang.language}: ${lang.shareA > 0 ? lang.shareA + '% share' : 'no recent repos'} | ${lang.repoChange} repos`;
};

let message = `📊 **GitHub Language Trends — ${$now.toFormat('yyyy-MM-dd')}**\n\n`;

if (rising.length) message += `📈 **Rising**\n${rising.map(fmt).join('\n')}\n\n`;
if (newLangs.length) message += `🆕 **New**\n${newLangs.map(fmt).join('\n')}\n\n`;
if (declining.length) message += `📉 **Declining**\n${declining.map(fmt).join('\n')}\n\n`;
if (dead.length) message += `💀 **Dead**\n${dead.map(fmt).join('\n')}\n\n`;
if (stable.length) message += `➡️ **Stable**\n${stable.map(fmt).join('\n')}`;
if (message.length > 1900) {
  message = message.substring(0, 1900) + '\n... (truncated)';
}
return [{ json: { Message: message } }];

const info = $input.first().json;

const errorMessage = info.error?.message || 'Unknown error';
const nodeName = info.error?.node?.name || 'Unknown node';
const workflowName = info.workflow?.name || 'Unknown workflow';
const executionUrl = info.execution?.url || 'No URL';

return [{
  json: {
    Message: `🚨 **Workflow Error: ${workflowName}**\n\n**Error:** ${errorMessage}\n**Node:** ${nodeName}\n**Time:** ${$now.toFormat('yyyy-MM-dd HH:mm:ss')}\n**Execution:** ${executionUrl}`
  }
}];
